1	import { useState } from "react";
2	import { Switch, Route, Router } from "wouter";
3	import { useHashLocation } from "wouter/use-hash-location";
4	import { queryClient } from "./lib/queryClient";
5	import { QueryClientProvider } from "@tanstack/react-query";
6	import { Toaster } from "@/components/ui/toaster";
7	import { TooltipProvider } from "@/components/ui/tooltip";
8	import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";
9	import { AppSidebar } from "@/components/app-sidebar";
10	import { ThemeProvider, useTheme } from "@/components/theme-provider";
11	
12	import { Button } from "@/components/ui/button";
13	import { Sun, Moon } from "lucide-react";
14	import NotFound from "@/pages/not-found";
15	import Dashboard from "@/pages/dashboard";
16	import Posts from "@/pages/posts";
17	import PostForm from "@/pages/post-form";
18	import ReviewQueue from "@/pages/review-queue";
19	import CalendarPage from "@/pages/calendar-page";
20	import Settings from "@/pages/settings";
21	
22	function ThemeToggle() {
23	  const { theme, toggleTheme } = useTheme();
24	  return (
25	    <Button
26	      variant="ghost"
27	      size="sm"
28	      onClick={toggleTheme}
29	      className="h-8 w-8 p-0"
30	      data-testid="button-theme-toggle"
31	    >
32	      {theme === "dark" ? (
33	        <Sun className="h-4 w-4" />
34	      ) : (
35	        <Moon className="h-4 w-4" />
36	      )}
37	    </Button>
38	  );
39	}
40	
41	function AppContent() {
42	  const [dealershipFilter, setDealershipFilter] = useState<number | null>(null);
43	
44	  const sidebarStyle = {
45	    "--sidebar-width": "16rem",
46	    "--sidebar-width-icon": "3rem",
47	  };
48	
49	  return (
50	    <SidebarProvider style={sidebarStyle as React.CSSProperties}>
51	      <div className="flex h-screen w-full">
52	        <AppSidebar
53	          dealershipFilter={dealershipFilter}
54	          onDealershipFilterChange={setDealershipFilter}
55	        />
56	        <div className="flex flex-col flex-1 min-w-0">
57	          <header className="flex items-center justify-between px-4 py-2 border-b border-border bg-background/80 backdrop-blur-sm">
58	            <SidebarTrigger data-testid="button-sidebar-toggle" />
59	            <ThemeToggle />
60	          </header>
61	          <main className="flex-1 overflow-auto">
62	            <Router hook={useHashLocation}>
63	              <Switch>
64	                <Route path="/" component={() => <Dashboard dealershipFilter={dealershipFilter} />} />
65	                <Route path="/posts" component={() => <Posts dealershipFilter={dealershipFilter} />} />
66	                <Route path="/posts/new" component={PostForm} />
67	                <Route path="/posts/:id" component={PostForm} />
68	                <Route path="/queue" component={() => <ReviewQueue dealershipFilter={dealershipFilter} />} />
69	                <Route path="/calendar" component={() => <CalendarPage dealershipFilter={dealershipFilter} />} />
70	                <Route path="/settings" component={Settings} />
71	                <Route component={NotFound} />
72	              </Switch>
73	            </Router>
74	
75	          </main>
76	        </div>
77	      </div>
78	    </SidebarProvider>
79	  );
80	}
81	
82	function App() {
83	  return (
84	    <QueryClientProvider client={queryClient}>
85	      <TooltipProvider>
86	        <ThemeProvider>
87	          <AppContent />
88	          <Toaster />
89	        </ThemeProvider>
90	      </TooltipProvider>
91	    </QueryClientProvider>
92	  );
93	}
94	
95	export default App;
