3	import {
4	  FileText,
5	  Edit3,
6	  ClipboardCheck,
7	  CalendarDays,
8	  CheckCircle2,
9	  PlusCircle,
10	  Activity,
11	} from "lucide-react";
12	import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
13	import { Button } from "@/components/ui/button";
14	import { Badge } from "@/components/ui/badge";
15	import { Skeleton } from "@/components/ui/skeleton";
16	import type { Dealership, ActivityLog } from "@shared/schema";
17	
18	interface DashboardData {
19	  stats: {
20	    total: number;
21	    draft: number;
22	    queued: number;
23	    scheduled: number;
24	    published: number;
25	  };
26	  dealerships: (Dealership & {
27	    postCount: number;
28	    scheduledCount: number;
29	    draftCount: number;
30	  })[];
31	  recentActivity: ActivityLog[];
32	}
33	
34	const kpiItems = [
35	  { key: "total" as const, label: "Total Posts", icon: FileText, color: "text-foreground" },
36	  { key: "draft" as const, label: "Drafts", icon: Edit3, color: "text-muted-foreground" },
37	  { key: "queued" as const, label: "Queued", icon: ClipboardCheck, color: "text-amber-500" },
38	  { key: "scheduled" as const, label: "Scheduled", icon: CalendarDays, color: "text-primary" },
39	  { key: "published" as const, label: "Published", icon: CheckCircle2, color: "text-green-500" },
40	];
41	
42	function formatTimeAgo(dateStr: string): string {
43	  const diff = Date.now() - new Date(dateStr).getTime();
44	  const mins = Math.floor(diff / 60000);
45	  if (mins < 1) return "Just now";
46	  if (mins < 60) return `${mins}m ago`;
47	  const hours = Math.floor(mins / 60);
48	  if (hours < 24) return `${hours}h ago`;
49	  const days = Math.floor(hours / 24);
50	  return `${days}d ago`;
51	}
52	
53	function getActionBadgeVariant(action: string): "default" | "secondary" | "destructive" | "outline" {
54	  switch (action) {
55	    case "published": return "default";
56	    case "scheduled": return "default";
57	    case "created": return "secondary";
58	    case "rejected": return "destructive";
59	    default: return "outline";
60	  }
61	}
62	
63	export default function Dashboard({ dealershipFilter }: { dealershipFilter: number | null }) {
64	  const { data, isLoading } = useQuery<DashboardData>({
65	    queryKey: ["/api/dashboard"],
66	  });
67	
68	  if (isLoading) {
69	    return (
70	      <div className="p-6 space-y-6">
71	        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
72	          {Array.from({ length: 5 }).map((_, i) => (
73	            <Skeleton key={i} className="h-24 rounded-lg" />
74	          ))}
75	        </div>
76	        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
77	          {Array.from({ length: 4 }).map((_, i) => (
78	            <Skeleton key={i} className="h-32 rounded-lg" />
79	          ))}
80	        </div>
81	      </div>
82	    );
83	  }
84	
85	  if (!data) return null;
86	
87	  const filteredDealerships = dealershipFilter
88	    ? data.dealerships.filter((d) => d.id === dealershipFilter)
89	    : data.dealerships;
90	
91	  return (
92	    <div className="p-6 space-y-6 max-w-[1400px]">
93	      {/* Page header */}
94	      <div className="flex items-center justify-between">
95	        <div>
96	          <h1 className="text-xl font-display font-semibold" data-testid="text-dashboard-title">
97	            Dashboard
98	          </h1>
99	          <p className="text-sm text-muted-foreground mt-0.5">
100	            Overview of your social content pipeline

