8	    throw new Error(`${res.status}: ${text}`);
9	  }
10	}
11	
12	export async function apiRequest(
13	  method: string,
14	  url: string,
15	  data?: unknown | undefined,
16	): Promise<Response> {
17	  const res = await fetch(`${API_BASE}${url}`, {
18	    method,
19	    headers: data ? { "Content-Type": "application/json" } : {},
20	    body: data ? JSON.stringify(data) : undefined,
21	  });
22	
23	  await throwIfResNotOk(res);
24	  return res;
25	}
26	
27	type UnauthorizedBehavior = "returnNull" | "throw";
28	export const getQueryFn: <T>(options: {
29	  on401: UnauthorizedBehavior;
30	}) => QueryFunction<T> =
31	  ({ on401: unauthorizedBehavior }) =>
32	  async ({ queryKey }) => {
33	    const res = await fetch(`${API_BASE}${queryKey.join("/")}`);
34	
35	    if (unauthorizedBehavior === "returnNull" && res.status === 401) {
36	      return null;
37	    }
38	
39	    await throwIfResNotOk(res);
40	    return await res.json();
41	  };
42	
43	export const queryClient = new QueryClient({
44	  defaultOptions: {
45	    queries: {
46	      queryFn: getQueryFn({ on401: "throw" }),
47	      refetchInterval: false,
48	      refetchOnWindowFocus: false,
49	      staleTime: Infinity,
50	      retry: false,
51	    },
52	    mutations: {
53	      retry: false,
54	    },
55	  },
56	});
