11	
12	import { Button } from "@/components/ui/button";
13	import { Sun, Moon } from "lucide-react";
14	import NotFound from "@/pages/not-found";
15	import Dashboard from "@/pages/dashboard";
16	import Posts from "@/pages/posts";
17	import PostForm from "@/pages/post-form";
18	import ReviewQueue from "@/pages/review-queue";
19	import CalendarPage from "@/pages/calendar-page";
20	import Settings from "@/pages/settings";
21	
22	function ThemeToggle() {
23	  const { theme, toggleTheme } = useTheme();
24	  return (
25	    <Button
26	      variant="ghost"
27	      size="sm"
28	      onClick={toggleTheme}
29	      className="h-8 w-8 p-0"
30	      data-testid="button-theme-toggle"
31	    >
32	      {theme === "dark" ? (
33	        <Sun className="h-4 w-4" />
