42	  const [dealershipFilter, setDealershipFilter] = useState<number | null>(null);
43	
44	  const sidebarStyle = {
45	    "--sidebar-width": "16rem",
46	    "--sidebar-width-icon": "3rem",
47	  };
48	
49	  return (
50	    <SidebarProvider style={sidebarStyle as React.CSSProperties}>
