58	            <SidebarTrigger data-testid="button-sidebar-toggle" />
59	            <ThemeToggle />
60	          </header>
61	          <main className="flex-1 overflow-auto">
62	            <Router hook={useHashLocation}>
63	              <Switch>
64	                <Route path="/" component={() => <Dashboard dealershipFilter={dealershipFilter} />} />
65	                <Route path="/posts" component={() => <Posts dealershipFilter={dealershipFilter} />} />
66	                <Route path="/posts/new" component={PostForm} />
67	                <Route path="/posts/:id" component={PostForm} />
68	                <Route path="/queue" component={() => <ReviewQueue dealershipFilter={dealershipFilter} />} />
69	                <Route path="/calendar" component={() => <CalendarPage dealershipFilter={dealershipFilter} />} />
70	                <Route path="/settings" component={Settings} />
71	                <Route component={NotFound} />
72	              </Switch>
73	            </Router>
74	
75	          </main>
76	        </div>
77	      </div>
78	    </SidebarProvider>
79	  );
80	}
81	
82	function App() {
83	  return (
84	    <QueryClientProvider client={queryClient}>
85	      <TooltipProvider>
86	        <ThemeProvider>
