1	import type { Express } from "express";
2	import type { Server } from "http";
3	import { storage } from "./storage";
4	import { insertPostSchema, insertDealershipSchema } from "@shared/schema";
5	import { scanDriveFolders, archiveFile } from "./drive-scanner";
6	import { publishPost } from "./zernio-publisher";
7	import { sendApprovalRequest, sendWeeklySummary } from "./telegram-notify";
8	
9	export async function registerRoutes(server: Server, app: Express) {
10	  // ---- Dealerships ----
11	  app.get("/api/dealerships", (_req, res) => {
12	    const dealerships = storage.getDealerships();
13	    res.json(dealerships);
14	  });
15	
16	  app.get("/api/dealerships/:id", (req, res) => {
17	    const dealership = storage.getDealership(Number(req.params.id));
18	    if (!dealership) return res.status(404).json({ error: "Not found" });
19	    res.json(dealership);
20	  });
21	
22	  app.post("/api/dealerships", (req, res) => {
23	    try {
24	      const data = insertDealershipSchema.parse(req.body);
25	      const dealership = storage.createDealership(data);
26	      res.status(201).json(dealership);
27	    } catch (err: any) {
28	      res.status(400).json({ error: err.message });
29	    }
30	  });
31	
32	  app.patch("/api/dealerships/:id", (req, res) => {
33	    const updated = storage.updateDealership(Number(req.params.id), req.body);
34	    if (!updated) return res.status(404).json({ error: "Not found" });
35	    res.json(updated);
36	  });
37	
38	  // ---- Posts ----
39	  app.get("/api/posts", (req, res) => {
40	    const filters: any = {};
41	    if (req.query.dealershipId) filters.dealershipId = Number(req.query.dealershipId);
42	    if (req.query.status) filters.status = req.query.status as string;
43	    if (req.query.postType) filters.postType = req.query.postType as string;
44	    const postsList = storage.getPosts(filters);
45	    res.json(postsList);
46	  });
47	
48	  app.get("/api/posts/stats", (_req, res) => {
49	    const stats = storage.getPostStats();
50	    res.json(stats);
51	  });
52	
53	  app.get("/api/posts/:id", (req, res) => {
54	    const post = storage.getPost(Number(req.params.id));
55	    if (!post) return res.status(404).json({ error: "Not found" });
56	    res.json(post);
57	  });
58	
59	  app.post("/api/posts", (req, res) => {
60	    try {
61	      const data = insertPostSchema.parse(req.body);
62	      const post = storage.createPost(data);
63	      storage.logActivity({
64	        postId: post.id,
65	        dealershipId: post.dealershipId,
66	        action: "created",
67	        details: `Post created: ${post.vehicleInfo || post.postType}`,
68	      });
69	      res.status(201).json(post);
70	    } catch (err: any) {
71	      res.status(400).json({ error: err.message });
72	    }
73	  });
74	
75	  app.patch("/api/posts/:id", (req, res) => {
76	    const existing = storage.getPost(Number(req.params.id));
77	    if (!existing) return res.status(404).json({ error: "Not found" });
78	
79	    const updated = storage.updatePost(Number(req.params.id), req.body);
80	    if (!updated) return res.status(500).json({ error: "Failed to update" });
81	
82	    // Log status changes
83	    if (req.body.status && req.body.status !== existing.status) {
84	      storage.logActivity({
85	        postId: updated.id,
86	        dealershipId: updated.dealershipId,
87	        action: req.body.status,
88	        details: `Post ${req.body.status}: ${updated.vehicleInfo || updated.postType}`,
89	      });
90	
91	      // Archive Drive file when post is scheduled or published
92	      if ((req.body.status === "scheduled" || req.body.status === "published") && updated.folderSource) {
93	        try {
94	          archiveFile(updated.dealershipId, updated.folderSource);
95	          console.log(`[Archive] Moved file to _Archive for post ${updated.id}`);
96	        } catch (e) {
97	          console.error(`[Archive] Failed to move file:`, e);
98	        }
99	      }
100	    }
101	
102	    res.json(updated);
103	  });
